const repos = [
  { ownerRepo: 'mrhz1973/control-plane', stateKey: 'github:mrhz1973/control-plane:last_commit_sha', sourceRepo: 'mrhz1973/control-plane' },
  { ownerRepo: 'mrhz1973/dev-method', stateKey: 'github:mrhz1973/dev-method:last_commit_sha', sourceRepo: 'mrhz1973/dev-method' },
  { ownerRepo: 'mrhz1973/cursor-coordinate-converter', stateKey: 'github:mrhz1973/cursor-coordinate-converter:last_commit_sha', sourceRepo: 'mrhz1973/cursor-coordinate-converter' }
];
return repos.map((r) => ({ json: r }));

const target = $('Emit watched repos (3)').item.json;
const resp = $input.item.json;
const commit = Array.isArray(resp) ? resp[0] : resp;
const sha = commit?.sha || '';
const rawMessage = commit?.commit?.message || 'no commit message';
const message = rawMessage.split('\n')[0];
const url = commit?.html_url || 'no URL';
return {
  json: {
    stateKey: target.stateKey,
    currentSha: sha,
    shortSha: sha ? sha.substring(0, 7) : '',
    message,
    url,
    sourceRepo: target.sourceRepo,
    ownerRepo: target.ownerRepo
  }
};

const prepareItems = $('Prepare latest commit event').all();
const stateRows = $('Data Table - Load all state rows').all().map((entry) => entry.json);
return prepareItems.map((item) => {
  const latest = item.json;
  const row = stateRows.find((r) => r.key === latest.stateKey);
  const storedValue = row?.value || '';
  const isNew = Boolean(latest.currentSha && latest.currentSha !== storedValue);
  return {
    json: {
      ...latest,
      previousSha: storedValue || '',
      isNew,
      hadStateRow: Boolean(row?.key)
    }
  };
});

const latest = $('Decide Data Table dedupe').item.json;
const previous = latest.previousSha ? latest.previousSha.substring(0, 7) : 'none';
return { json: { text: `CONTROL PLANE scheduled poll commit notification
Repo: ${latest.sourceRepo}
New commit: ${latest.shortSha}
Previous: ${previous}
Message: ${latest.message}
URL: ${latest.url}` } };

const repo = String($json.ownerRepo || $json.sourceRepo || '').trim();
const isControlPlane = repo === 'mrhz1973/control-plane';
return { json: { event: isControlPlane ? 'plan_branch_entered' : 'plan_branch_skipped', repo, stateKey: $json.stateKey, currentSha: $json.currentSha, shortSha: $json.shortSha, latestCommitUrl: $json.url, latestCommitMessage: $json.message, previousSha: $json.previousSha, gate: 'C-production-candidate', activeRuntimeTarget: '40 - CP v4 multirepo polling - FILE HANDOFF SAFE TEXT - ACTIVE', gateD: 'not_authorized', noGateDTelegram: true } };

const commit = $input.first().json;
const gate = $('Code - Plan watcher repo gate stub').first().json;
const files = Array.isArray(commit.files) ? commit.files : [];
const planFiles = files.filter((f) => {
  const name = String(f.filename || '');
  return /^docs\/plans\/[^/]+\.plan\.md$/.test(name);
});
if (!planFiles.length) {
  return [{ json: { event: 'no_plan_detected', repo: gate.repo, commitSha: gate.currentSha, shortSha: gate.shortSha, changedFileCount: files.length, changedFiles: files.map(f => f.filename).slice(0, 30), gate: 'C-production-candidate', gateD: 'not_authorized' } }];
}
return planFiles.map((f) => ({ json: { event: 'plan_detected', repo: gate.repo, commitSha: gate.currentSha, shortSha: gate.shortSha, planPath: f.filename, fileStatus: f.status || '', additions: f.additions ?? null, deletions: f.deletions ?? null, changes: f.changes ?? null, gate: 'C-production-candidate', nextGate: 'Gate D message delivery not authorized' } }));
